    for (const o of owners) await c.query('INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1,$2,$3,$4,$5,$6)', [requestId, accountId, o, o + " recovery owner task", now, "open"]);
